// Weight Tuner â Daily autonomous weight optimizer
// Reads last 60 signals, evaluates each against current price,
// computes EMA-weighted accuracy per regime, updates strategy weights.
const tickerRaw = $('WT Fetch BTC Price').first().json;
const tickerResult = tickerRaw && tickerRaw.result ? tickerRaw.result : {};
const tickerKey = Object.keys(tickerResult)[0];
const ticker = tickerResult[tickerKey] || {};
const currentPrice = ticker.c ? parseFloat(ticker.c[0]) : 0;

const vaultRaw = $('WT Read Signals').first().json;
const memories = (vaultRaw && vaultRaw.memories) ? vaultRaw.memories : [];

if (currentPrice === 0 || memories.length === 0) {
  return [{ json: { error: 'No data available', skipped: true, reason: 'BTC price: ' + currentPrice + ', memories: ' + memories.length } }];
}

const now = Date.now();
const results = [];

// Evaluate each stored signal against current price
for (const mem of memories) {
  const content = mem.content || '';
  if (!content.includes('TRADE SIGNAL')) continue;
  const dirMatch   = content.match(/TRADE SIGNAL[^:]*:\s*(BUY|SELL|WAIT)\s+BTC/);
  const priceMatch = content.match(/@ \$([\d,]+(?:\.\d+)?)/);
  const confMatch  = content.match(/Confidence:([\d.]+)%/);
  const regMatch   = content.match(/Regime:(\w+)/);
  const hurstMatch = content.match(/Hurst:([\d.]+)\((\w+)\)/);
  if (!dirMatch || !priceMatch) continue;
  const dir = dirMatch[1];
  if (dir === 'WAIT') continue;
  const signalPrice = parseFloat(priceMatch[1].replace(/,/g, ''));
  const conf = confMatch ? parseFloat(confMatch[1]) : 50;
  const regime = regMatch ? regMatch[1] : 'UNKNOWN';
  const hurstR = hurstMatch ? hurstMatch[2] : 'RANDOM';
  if (signalPrice === 0) continue;
  const createdAt = mem.created_at || '';
  const ageSecs = createdAt ? (now - new Date(createdAt).getTime()) / 1000 : 86400;
  if (ageSecs > 72 * 3600) continue; // only look at last 72 hours
  const minMove = ageSecs < 3600 ? 0.3 : ageSecs < 14400 ? 0.6 : 1.0;
  const pctMove = ((currentPrice - signalPrice) / signalPrice) * 100;
  if (Math.abs(pctMove) < minMove) continue; // too soon
  const correct = (dir === 'BUY' && pctMove > 0) || (dir === 'SELL' && pctMove < 0);
  // Exponential time-decay: recent signals weighted 2x vs 24h-old
  const decayWeight = Math.exp(-ageSecs / (24 * 3600));
  results.push({ dir, regime, hurstR, conf, correct, decayWeight, ageSecs, pctMove });
}

const gradeable = results.length;
if (gradeable === 0) {
  return [{ json: { error: 'No gradeable signals in last 72h', skipped: true } }];
}

// Compute weighted overall hit rate
const wtCorrect = results.reduce((s, r) => s + (r.correct ? r.decayWeight : 0), 0);
const wtTotal   = results.reduce((s, r) => s + r.decayWeight, 0);
const hitRate   = Math.round(wtCorrect / wtTotal * 100);

// Per-direction weighted accuracy
const buyResults  = results.filter(r => r.dir === 'BUY');
const sellResults = results.filter(r => r.dir === 'SELL');
const buyWtC  = buyResults.reduce((s, r) => s + (r.correct ? r.decayWeight : 0), 0);
const buyWtT  = buyResults.reduce((s, r) => s + r.decayWeight, 0);
const sellWtC = sellResults.reduce((s, r) => s + (r.correct ? r.decayWeight : 0), 0);
const sellWtT = sellResults.reduce((s, r) => s + r.decayWeight, 0);
const buyHitRate  = buyWtT  > 0.1 ? Math.round(buyWtC  / buyWtT  * 100) : 50;
const sellHitRate = sellWtT > 0.1 ? Math.round(sellWtC / sellWtT * 100) : 50;

// Per-regime weighted accuracy
const regimeStats = {};
for (const r of results) {
  if (!regimeStats[r.regime]) regimeStats[r.regime] = { wtC: 0, wtT: 0 };
  regimeStats[r.regime].wtT += r.decayWeight;
  if (r.correct) regimeStats[r.regime].wtC += r.decayWeight;
}

// Hurst-based routing: which strategy family fits the market character?
const trendResults  = results.filter(r => r.hurstR === 'TREND');
const meanRevResults = results.filter(r => r.hurstR === 'MEAN_REV');
const trendWtC  = trendResults.reduce((s, r) => s + (r.correct ? r.decayWeight : 0), 0);
const trendWtT  = trendResults.reduce((s, r) => s + r.decayWeight, 0);
const mrWtC     = meanRevResults.reduce((s, r) => s + (r.correct ? r.decayWeight : 0), 0);
const mrWtT     = meanRevResults.reduce((s, r) => s + r.decayWeight, 0);
const trendHR   = trendWtT  > 0.5 ? trendWtC  / trendWtT  : 0.5;
const meanRevHR = mrWtT     > 0.5 ? mrWtC     / mrWtT     : 0.5;

// Map regimes to strategy families
const regimeToStrat = {
  BULL_TREND_STRONG:  ['trend','multiTF','momentum'],
  BULL_TREND_WEAK:    ['trend','multiTF'],
  BEAR_TREND_STRONG:  ['trend','multiTF','momentum'],
  BEAR_TREND_WEAK:    ['trend','multiTF'],
  RANGE_BOUND:        ['meanRev','smc','fibonacci'],
  BREAKOUT_BULL:      ['breakout','momentum','micro'],
  BREAKOUT_BEAR:      ['breakout','momentum','micro'],
  HIGH_VOL_EXPAND:    ['breakout','momentum'],
  LOW_VOL_COMPRESS:   ['meanRev','fibonacci'],
  RISK_ON:            ['macro','multiTF'],
  RISK_OFF:           ['macro','stat'],
  EXTREME_CAUTION:    ['macro','stat'],
};

// Base weights â EMA update: new = (1-alpha)*current + alpha*target
const alpha = 0.25; // learning rate â conservative to prevent overfitting
const defaultWt = { trend:1.5, meanRev:1.0, momentum:1.2, breakout:1.1, smc:1.3, multiTF:1.8, fibonacci:0.9, macro:1.3, micro:1.3, stat:0.8 };
const adaptiveWt = Object.assign({}, defaultWt);
const adjustments = {};

for (const [regime, stats] of Object.entries(regimeStats)) {
  if (stats.wtT < 0.8) continue; // need meaningful signal mass
  const regHR = stats.wtC / stats.wtT;
  // Target adjustment: max Â±0.25 per cycle
  const targetDelta = Math.max(-0.25, Math.min(0.25, (regHR - 0.55) * 1.5));
  const strats = regimeToStrat[regime] || [];
  for (const s of strats) {
    if (adaptiveWt[s] !== undefined) {
      const emaTarget = defaultWt[s] + targetDelta;
      // EMA smoothing: blend toward target
      adaptiveWt[s] = Math.round(((1 - alpha) * adaptiveWt[s] + alpha * emaTarget) * 100) / 100;
      adaptiveWt[s] = Math.max(0.4, Math.min(2.8, adaptiveWt[s]));
      adjustments[s] = (adjustments[s] || 0) + targetDelta;
    }
  }
}

// Additional: Hurst-based overlay â if trend-following works better, boost trend family
if (trendWtT > 0.5 && meanRevHR > 0 && trendHR > 0) {
  const hurstDelta = (trendHR - meanRevHR) * 0.2; // up to 0.2 weight shift
  adaptiveWt['trend']   = Math.round(Math.max(0.4, Math.min(2.8, adaptiveWt['trend']   + hurstDelta)) * 100) / 100;
  adaptiveWt['meanRev'] = Math.round(Math.max(0.4, Math.min(2.8, adaptiveWt['meanRev'] - hurstDelta)) * 100) / 100;
}

// Normalize weights to preserve total magnitude
const origSum = Object.values(defaultWt).reduce((a, b) => a + b, 0);
const newSum  = Object.values(adaptiveWt).reduce((a, b) => a + b, 0);
if (newSum > 0.1) {
  for (const k of Object.keys(adaptiveWt)) {
    adaptiveWt[k] = Math.round(adaptiveWt[k] / newSum * origSum * 100) / 100;
  }
}

// Adaptive minConf
let adaptiveMinConf = 60;
if (gradeable >= 10) {
  if      (hitRate < 40)  adaptiveMinConf = 68;
  else if (hitRate < 48)  adaptiveMinConf = 65;
  else if (hitRate < 55)  adaptiveMinConf = 62;
  else if (hitRate > 72)  adaptiveMinConf = 56;
  else if (hitRate > 65)  adaptiveMinConf = 58;
  else                    adaptiveMinConf = 60;
}

const buyMult  = gradeable >= 8 ? parseFloat(Math.max(0.80, Math.min(1.20, 0.50 + (buyHitRate  / 100))).toFixed(2)) : 1.0;
const sellMult = gradeable >= 8 ? parseFloat(Math.max(0.80, Math.min(1.20, 0.50 + (sellHitRate / 100))).toFixed(2)) : 1.0;

const regimeStatsSummary = Object.fromEntries(
  Object.entries(regimeStats).map(([r, s]) => [r, Math.round(s.wtC/s.wtT*100) + '%w (' + results.filter(x=>x.regime===r).length + 'sig)'])
);


// âââ DEFLATED SHARPE GATE (Bailey & Lopez de Prado 2014) ââââââââââââââ
// Compute approximate Sharpe ratio of the realized returns and check if
// it exceeds the noise threshold given # of trials. Only promote new
// weights if statistically significant.
const realizedRets = results.map(r => (r.correct ? 1 : -1) * r.decayWeight);
let dsrPass = false, dsr = null, sharpeRaw = null;
if (realizedRets.length >= 15) {
  const mean = realizedRets.reduce((a,b) => a+b, 0) / realizedRets.length;
  const sd   = Math.sqrt(realizedRets.reduce((s,r) => s + (r-mean)**2, 0) / (realizedRets.length-1));
  if (sd > 0) {
    sharpeRaw = mean / sd;
    // Skewness and kurtosis of returns
    const skew = realizedRets.reduce((s,r) => s + ((r-mean)/sd)**3, 0) / realizedRets.length;
    const kurt = realizedRets.reduce((s,r) => s + ((r-mean)/sd)**4, 0) / realizedRets.length;
    // Critical Sharpe with N trials (we explore ~10 weight configurations)
    const numTrials = 10;
    const sr0 = Math.sqrt(2 * Math.log(numTrials)) - Math.log(Math.log(numTrials));
    const sigmaSR = Math.sqrt((1 - skew * sharpeRaw + ((kurt - 1)/4) * sharpeRaw**2) / (realizedRets.length - 1));
    if (sigmaSR > 0) {
      dsr = (sharpeRaw - sr0 * sigmaSR) / sigmaSR;
      dsrPass = dsr > 1.96; // 95% confidence
    }
  }
}

// If DSR fails, keep weights at default (don't promote noise)
if (!dsrPass && realizedRets.length >= 15) {
  for (const k of Object.keys(adaptiveWt)) adaptiveWt[k] = defaultWt[k];
}
