const adaptiveParams = 'ADAPTIVE_PARAMS | ' + new Date().toISOString().slice(0,16) + 'Z'
  + ' | minConf:' + adaptiveMinConf
  + ' | buyMult:' + buyMult
  + ' | sellMult:' + sellMult
  + ' | hitRate:' + hitRate + '%'
  + ' | buyHR:' + buyHitRate + '%'
  + ' | sellHR:' + sellHitRate + '%'
  + ' | highConfHR:' + wt_highConfHR + '%' + ' | lowConfHR:' + wt_lowConfHR + '%' + ' | confCalibrated:' + wt_confCalibrated
  + ' | gradeable:' + gradeable
  + ' | wt:' + JSON.stringify(adaptiveWt)
  + ' | regimeStats:' + JSON.stringify(regimeStatsSummary)
  + ' | dataQuality:' + (gradeable < 5 ? 'INSUFFICIENT' : gradeable < 15 ? 'BUILDING' : 'SUFFICIENT')
  + ' | dsr:' + (dsr === null ? 'NA' : dsr.toFixed(2)) + ' | dsrPass:' + dsrPass + ' | sharpeRaw:' + (sharpeRaw === null ? 'NA' : sharpeRaw.toFixed(3))
  + ' | trendHR:' + Math.round(trendHR*100) + '%'
  + ' | meanRevHR:' + Math.round(meanRevHR*100) + '%';

const report = 'WEIGHT TUNER REPORT | ' + new Date().toISOString().slice(0,16) + 'Z'
  + '\nBTC @ $' + Math.round(currentPrice) + ' | Signals analyzed: ' + memories.length + ' | Gradeable (72h): ' + gradeable
  + '\nWeighted hit rate: ' + hitRate + '% | BUY: ' + buyHitRate + '% | SELL: ' + sellHitRate + '%'
  + '\nTrend-regime HR: ' + Math.round(trendHR*100) + '% | MeanRev-regime HR: ' + Math.round(meanRevHR*100) + '%'
  + '\nNew weights: ' + JSON.stringify(adaptiveWt)
  + '\nAdjustments: ' + JSON.stringify(adjustments)
  + '\nAdaptive minConf: ' + adaptiveMinConf;

return [{ json: { adaptiveParams, report, hitRate, dsr, dsrPass, sharpeRaw, buyHitRate, sellHitRate, gradeable, adaptiveWt, adaptiveMinConf, buyMult, sellMult, regimeStatsSummary, adjustments } }];

// Weight Tuner: Write Adaptive Params to inspiring-cat vault
const https = require('https');
const data = $input.first().json;
const adaptiveParams = data.adaptiveParams;

if (!adaptiveParams || data.skipped) {
  return [{ json: { stored: false, reason: data.error || data.reason || 'skipped' } }];
}

const payload = JSON.stringify({
  memories: [{
    content: adaptiveParams,
    source: 'weight_tuner',
    memory_type: 'adaptive',
    importance: 5,
    tags: ['crypto_adaptive_params', 'performance', 'learning', 'weight_tuner']
  }]
});

const result = await new Promise((resolve) => {
  const opts = {
    hostname: 'inspiring-cat-production.up.railway.app',
    path: '/memory/ingest',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-Memory-Secret': '2dc6c69574c14d615ce146e54640aa13030dade7aa86697c',
      'Content-Length': Buffer.byteLength(payload)
    }
  };
  const req = https.request(opts, (res) => {
    let d = '';
    res.on('data', c => d += c);
    res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { resolve({ ok: false, err: d.slice(0,80) }); } });
  });
  req.on('error', e => resolve({ ok: false, err: e.message }));
  req.setTimeout(8000, () => { req.destroy(); resolve({ ok: false, err: 'timeout' }); });
  req.write(payload);
  req.end();
});

return [{ json: { stored: !!result.ok, result, preview: adaptiveParams.slice(0, 150) } }];
